def solve(h,w,k,s):
    dp = [[[0] * (k + 1) for _ in range(w + 1)] for _ in range(h + 1)]
    for i in range(1,h+1):
        for j in range(1,w+1):
            for l in range(k + 1):
                if s[i-1][j-1] == 0:
                    dp[i][j][l] = dp[i-1][j][l] + dp[i][j-1][l] - dp[i-1][j-1][l]
                else:
                    if l == 0:
                        dp[i][j][l] = dp[i-1][j][l] + dp[i][j-1][l] - dp[i-1][j-1][l] + 1
                    else:
                        dp[i][j][l] = dp[i-1][j][l-1] + dp[i][j-1][l] - dp[i-1][j-1][l] + dp[i-1][j-1][l-1]
    return dp[h][w][k]

h,w,k = map(int,input().split())
s = [list(map(int,input())) for _ in range(h)]
print(solve(h,w,k,s))
